#!/usr/bin/env python3
"""Curated research-backed POIs for OceanScout (maritime) and LandShift (land-use change).

Coordinates are approximate hub / open-water / frontier centers suitable for Sentinel-2
chips (ports, estuaries, chokepoints; ag expansion, deforestation arcs, peri-urban).

Run: python data/scripts/research_poi_catalog.py
Writes: data/events/oceanscout_pois.json, data/events/landshift_pois.json

Core lists live below; additional POIs are merged from research_poi_catalog_extra.py
(Lloyd's Top 100 / WSC-style hubs, GFW-style deforestation frontiers) with dedupe on event_id.
"""

from __future__ import annotations

import json
from pathlib import Path

from research_poi_catalog_extra import LANDSHIFT_POIS_EXTRA, OCEANSCOUT_POIS_EXTRA

REPO = Path(__file__).resolve().parents[2]


def _merge_dedupe_pois(*parts: list[dict]) -> list[dict]:
    """Concatenate POI dict lists; first occurrence of event_id wins."""
    seen: set[str] = set()
    out: list[dict] = []
    for part in parts:
        for row in part:
            eid = str(row.get("event_id", ""))
            if not eid or eid in seen:
                continue
            seen.add(eid)
            out.append(row)
    return out


