LANDSHIFT_POIS = _merge_dedupe_pois(LANDSHIFT_POIS_CORE, LANDSHIFT_POIS_EXTRA)


def main() -> None:
    ev_dir = REPO / "data" / "events"
    ev_dir.mkdir(parents=True, exist_ok=True)
    (ev_dir / "oceanscout_pois.json").write_text(json.dumps(OCEANSCOUT_POIS, indent=2), encoding="utf-8")
    (ev_dir / "landshift_pois.json").write_text(json.dumps(LANDSHIFT_POIS, indent=2), encoding="utf-8")
    print(f"Wrote {len(OCEANSCOUT_POIS)} OceanScout + {len(LANDSHIFT_POIS)} LandShift POIs to {ev_dir}")


if __name__ == "__main__":
    main()
